{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires finding an optimal layout of colored regions on a 50x50 grid. Since the specific input map (the colors and their adjacency requirements) is not provided in the prompt, the helpers must focus on the algorithmic logic of mapping a graph to a grid while maximizing empty space.",
  "helpers": [
    {
      "label": "graph_to_grid_mapper",
      "instructions": "Given a set of colored regions and their adjacency requirements, generate a 50x50 grid layout that places each region such that all required color-to-color adjacencies are satisfied via orthogonal cell contact, while minimizing the total number of cells occupied by colors."
    },
    {
      "label": "empty_space_calculator",
      "instructions": "Given a 50x50 grid layout where cells are either colored or empty, count the total number of empty cells E and calculate the final score E + 1."
    }
  ],
  "synthesis_brief": "The parent will take the grid layout generated by the first helper and pass it to the second helper to calculate the score. If the input map is provided, the final answer will be the grid layout and the calculated score."
}

